"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { days } from "@/lib/diary";
import { useState } from "react";

export default function Sidebar() {
  const pathname = usePathname();
  const [personalOpen, setPersonalOpen] = useState(true);

  if (pathname === "/login") return null;

  const linkClass = (href: string) =>
    `block text-sm transition-colors ${
      pathname === href
        ? "text-zinc-100 font-medium"
        : "text-zinc-500 hover:text-zinc-300"
    }`;

  const dayLinkClass = (slug: string) =>
    `block text-sm transition-colors pl-4 ${
      pathname === `/personal/${slug}`
        ? "text-zinc-100 font-medium"
        : "text-zinc-600 hover:text-zinc-300"
    }`;

  return (
    <aside className="w-56 shrink-0 min-h-screen border-r border-zinc-800 bg-zinc-900/50 flex flex-col py-8 px-4">
      <Link href="/" className="text-lg font-bold tracking-tight text-zinc-100 mb-8 hover:text-accent transition-colors">
        Distillery
      </Link>

      <nav className="flex flex-col gap-1">
        <Link href="/" className={linkClass("/")}>
          Feed
        </Link>
        <Link href="/sources" className={linkClass("/sources")}>
          Sources
        </Link>
      </nav>

      <div className="mt-8">
        <button
          onClick={() => setPersonalOpen(!personalOpen)}
          className="flex items-center gap-1.5 text-xs font-semibold uppercase tracking-wider text-zinc-500 hover:text-zinc-300 transition-colors w-full text-left"
        >
          <span className={`transition-transform ${personalOpen ? "rotate-90" : ""}`}>▶</span>
          Personal
        </button>
        {personalOpen && (
          <div className="mt-2 flex flex-col gap-0.5">
            {days.map((day) => (
              <Link
                key={day.slug}
                href={`/personal/${day.slug}`}
                className={dayLinkClass(day.slug)}
              >
                {day.title}
              </Link>
            ))}
          </div>
        )}
      </div>
    </aside>
  );
}
